import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Select, DateRangeFilter, addToast, CatalogTableSkeleton } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { useProcessingLevelLabels } from '../../hooks/useProcessingLevelLabels';
import { useVoucherListFilterState } from '../../hooks/useVoucherListFilterState';
import { LIST_FILTER_SCOPE } from '../../constants/listFilterScopes';
import { ktService } from '../../services/kt/ktService';
import type { CashVoucherDto } from '../../services/kt/models';
import { formatDateLocal, formatVnd } from '../../utils/formatters';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import { ProcessingLevelApproveModal } from '../voucher/ProcessingLevelApproveModal';
import erp from '../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../list/ListSearchRefreshButtons';
import {
  DEFAULT_VOUCHER_LIST_PAGE_SIZE,
  VoucherListPagination,
  type VoucherListPageSize,
} from '../list/VoucherListPagination';
import { useVoucherListTableBusy } from '../list/useVoucherListTableBusy';

const PAGE_SIZE = DEFAULT_VOUCHER_LIST_PAGE_SIZE;
export type CashVoucherKind = 'receipt' | 'payment';

const CONFIG = {
  receipt: {
    title: 'Phiếu thu',
    icon: 'fa-file-invoice-dollar',
    createPath: '/kt/pt/them',
    detailPath: (id: string) => `/kt/pt/${id}`,
    fetch: ktService.getReceipts,
    batchUpdateProcessingLevel: ktService.batchUpdateReceiptProcessingLevel,
    listScope: LIST_FILTER_SCOPE.phieuThu,
  },
  payment: {
    title: 'Phiếu chi',
    icon: 'fa-money-bill-wave',
    createPath: '/kt/pc/them',
    detailPath: (id: string) => `/kt/pc/${id}`,
    fetch: ktService.getPayments,
    batchUpdateProcessingLevel: ktService.batchUpdatePaymentProcessingLevel,
    listScope: LIST_FILTER_SCOPE.phieuChi,
  },
} as const;

function isRowSelectable(row: CashVoucherDto): boolean {
  return row.status === 'Draft';
}

export const CashVoucherList: React.FC<{ kind: CashVoucherKind }> = ({ kind }) => {
  const cfg = CONFIG[kind];
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const {
    initialized,
    fromDate,
    setFromDate,
    toDate,
    setToDate,
    processingLevel,
    setProcessingLevel,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(cfg.listScope);
  const [items, setItems] = useState<CashVoucherDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<VoucherListPageSize>(PAGE_SIZE);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [approving, setApproving] = useState(false);

  const testIdPrefix = kind === 'receipt' ? 'kt-phieu-thu' : 'kt-phieu-chi';
  const { levelOptions, filterOptions, formatLabel } = useProcessingLevelLabels(kind);
  const { showTableLoading, pulseSearch } = useVoucherListTableBusy(loading);

  const selectableOnPage = useMemo(
    () => items.filter(isRowSelectable),
    [items],
  );
  const allSelectableSelected = selectableOnPage.length > 0
    && selectableOnPage.every(r => selectedIds.includes(r.id));

  const handleSearch = () => {
    pulseSearch(() => {
      setPage(1);
      setSelectedIds([]);
      setReloadKey(k => k + 1);
    });
  };
  const refresh = () => {
    setSelectedIds([]);
    setReloadKey(k => k + 1);
  };

  const setPageSize = (size: number) => {
    setPageSizeState(size as VoucherListPageSize);
    setPage(1);
    setSelectedIds([]);
  };

  React.useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      cfg.fetch({
        fromDate,
        toDate,
        processingLevel: processingLevel || undefined,
        page,
        pageSize,
      })
        .then(res => { if (!cancelled) { setItems(res.items); setTotalCount(res.totalCount); } })
        .catch(err => {
          if (!cancelled) {
            dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải danh sách'), type: 'error' }));
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, fromDate, toDate, processingLevel, page, pageSize, kind, reloadKey, dispatch, cfg]);

  const toggleRow = (id: string, checked: boolean) => {
    setSelectedIds(prev => (checked ? [...prev, id] : prev.filter(x => x !== id)));
  };

  const toggleSelectAll = () => {
    if (allSelectableSelected) {
      const pageIds = new Set(selectableOnPage.map(r => r.id));
      setSelectedIds(prev => prev.filter(id => !pageIds.has(id)));
    } else {
      const merged = new Set([...selectedIds, ...selectableOnPage.map(r => r.id)]);
      setSelectedIds([...merged]);
    }
  };

  const handleBatchApproveConfirm = async (newLevel: string) => {
    setApproving(true);
    try {
      await cfg.batchUpdateProcessingLevel({ ids: selectedIds, processingLevel: newLevel });
      dispatch(addToast({ message: 'Phê duyệt thành công', type: 'success' }));
      setShowApproveModal(false);
      setSelectedIds([]);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({
        message: getApiErrorMessage(err, 'Phê duyệt thất bại. Vui lòng thử lại.'),
        type: 'error',
      }));
    } finally {
      setApproving(false);
    }
  };

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <h1 className={erp.title}><i className={`fas ${cfg.icon}`} /> {cfg.title}</h1>
        </div>
        <div className={erp.headerActions}>
          <Button
            variant="secondary"
            data-testid={`${testIdPrefix}-batch-approve-btn`}
            disabled={selectedIds.length === 0}
            onClick={() => setShowApproveModal(true)}
          >
            <i className="fas fa-check-double" /> Phê duyệt
          </Button>
          <Button variant="primary" onClick={() => navigate(cfg.createPath)}>
            <i className="fas fa-plus" /> Tạo mới
          </Button>
        </div>
      </div>

      {selectedIds.length > 0 && (
        <div className={erp.batchBar} data-testid={`${testIdPrefix}-batch-bar`}>
          <span>Đã chọn {selectedIds.length}</span>
          <button
            type="button"
            className={erp.batchBarLink}
            data-testid={`${testIdPrefix}-batch-clear`}
            onClick={() => setSelectedIds([])}
          >
            Bỏ chọn tất cả
          </button>
        </div>
      )}

      <div className={erp.filtersBar} data-testid={`${testIdPrefix}-filters`}>
        <DateRangeFilter
          fromDate={fromDate}
          toDate={toDate}
          onChange={(v: DateRangeValue) => {
            setFromDate(v.fromDate);
            setToDate(v.toDate);
            resetPage();
          }}
        />
        <div data-testid={`${testIdPrefix}-filter-processingLevel`}>
          <Select
            value={processingLevel}
            onChange={e => { setProcessingLevel(e.target.value); resetPage(); }}
            options={filterOptions}
          />
        </div>
        <ListSearchRefreshButtons testIdPrefix={testIdPrefix} onSearch={handleSearch} onRefresh={refresh} />
      </div>

      <div className={erp.tableCard}>
        {showTableLoading ? (
          <CatalogTableSkeleton
            rows={Math.min(pageSize, 8)}
            data-testid={`${testIdPrefix}-table-skeleton`}
          />
        ) : items.length === 0 ? (
          <div className={erp.empty}>Không có dữ liệu</div>
        ) : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead>
                <tr>
                  <th className={erp.colCheck}>
                    <input
                      type="checkbox"
                      data-testid={`${testIdPrefix}-select-all`}
                      checked={allSelectableSelected}
                      disabled={selectableOnPage.length === 0}
                      onChange={toggleSelectAll}
                      aria-label="Chọn tất cả"
                    />
                  </th>
                  <th>Số phiếu</th>
                  <th>Ngày</th>
                  <th>Đối tác</th>
                  <th>Diễn giải</th>
                  <th className={erp.colAmount}>Số tiền</th>
                  <th>Mức xử lý</th>
                </tr>
              </thead>
              <tbody>
                {items.map(r => {
                  const selectable = isRowSelectable(r);
                  return (
                    <tr key={r.id}>
                      <td className={erp.colCheck}>
                        <input
                          type="checkbox"
                          data-testid={`${testIdPrefix}-row-${r.id}-select`}
                          checked={selectedIds.includes(r.id)}
                          disabled={!selectable}
                          onChange={e => toggleRow(r.id, e.target.checked)}
                          aria-label={`Chọn ${r.code}`}
                        />
                      </td>
                      <td>
                        <button
                          type="button"
                          className={erp.codeLink}
                          onClick={() => navigate(cfg.detailPath(r.id))}
                        >
                          <code>{r.code}</code>
                        </button>
                      </td>
                      <td>{formatDateLocal(r.voucherDate)}</td>
                      <td>{r.customerName ?? '—'}</td>
                      <td>{r.description}</td>
                      <td className={erp.amountCell}>{formatVnd(r.amount)}</td>
                      <td data-testid={`${testIdPrefix}-row-${r.id}-processing-level`}>
                        {formatLabel(r.processingLevel)}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
        {!showTableLoading && (
          <VoucherListPagination
            testIdPrefix={testIdPrefix}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); setSelectedIds([]); }}
            onPageSizeChange={setPageSize}
          />
        )}
      </div>

      <ProcessingLevelApproveModal
        isOpen={showApproveModal}
        onClose={() => setShowApproveModal(false)}
        currentLevel={String(levelOptions[0]?.value ?? '3')}
        levelOptions={levelOptions}
        onConfirm={handleBatchApproveConfirm}
        saving={approving}
        testIdPrefix={testIdPrefix}
      />
    </div>
  );
};
